sys_script_include.script:
var EnrollmentService = Class.create();
EnrollmentService.prototype = {
	initialize: function () {
		this.httpRequestUtils = new HttpRequestUtils();
		this.glideRecordUtils = new GlideRecordUtils();
		this.profileService = new ProfileService();
		this.certificateService = new CertificateService();
		this.logger = new Logger('EnrollmentService');
	},
	// Create enrollment for manual approval
	createManualEnrollment: function (certificateRequestGr) {
		this.logger.debug(
			'createManualEnrollment(): Start creating enrollment for manual approval for Certificate Request sys_id: {0}',
			certificateRequestGr.sys_id
		);

		var certificateRequest = this.glideRecordUtils.getGrObject(certificateRequestGr);
		var profile = this.profileService.getProfileInfoBySysId(certificateRequest.profile.value);
		var csr = certificateRequest.csr.value;
		var enrollmentMethod = profile.enrollment_method.value;
		var authMethod = profile.authentication_method.value;
		var oldCertSerialNumber = certificateRequest.old_certificate_serial_number.value;

		var isCSRFlow = authMethod === Constants.AUTHENTICATION_METHODS.MANUAL_APPROVAL && enrollmentMethod === Constants.ENROLLMENT_METHODS.CSR;
		var isManualEnrollmentRenewal = certificateRequest.is_manual_approval_renewal.value;

		var oldCertId = "";

		var params = {
			profile: {
				id: profile.id.value,
			},
			email: certificateRequest.enrollment_email.value,
			attributes: JSON.parse(certificateRequest.attributes.value),
		};

		if (isManualEnrollmentRenewal) {
			params = {
				profile: {
					id: profile.id.value
				}
			};
			certificateDetails = this.certificateService.getCertificateDetailsBySerialNumber(oldCertSerialNumber);
			oldCertId = certificateDetails.id;
		}

		if (isCSRFlow) {
			params.csr = csr;
		}


		this.logger.debug(
			'createManualEnrollment(): params for manual-enrollment HTTP request: {0}',
			JSON.stringify(params)
		);



		try {
			var renewalManualAuthUrl = Constants.URL.manualRenewalUrl.replace('{old_cert_id}', oldCertId);
			var renewalUrl = isManualEnrollmentRenewal ? renewalManualAuthUrl : Constants.URL.manualEnrollmentUrl;
			var enrollment = this.httpRequestUtils.post(renewalUrl, params);
			enrollment = JSON.parse(enrollment);
		} catch (error) {
			this.logger.error(
				'createManualEnrollment(): Error ocurred on creating enrollment for manual approval: {0}',
				error.message
			);
			throw error;
		}

		certificateRequestGr.enrollment_id = enrollment.id;

		if (enrollment.enrollment_id) {
			certificateRequestGr.enrollment_id = enrollment.enrollment_id;
			enrollment.id = enrollment.enrollment_id;
			enrollment.is_approved = true;
		}

		certificateRequestGr.update();

		this.logger.info(
			'createManualEnrollment(): Enrollment for Certificate Request sys_id {0} has been successfully created',
			certificateRequestGr.sys_id
		);

		return enrollment;
	},

	approveManualEnrollment: function (enrollmentData, certificateRequestSysId) {
		var enrollmentId = enrollmentData.id;
		var isAutoApproved = enrollmentData.is_approved;
		this.logger.debug(
			'approveManualEnrollment(): Changing enrollment status to approved. certificateRequestSysId: {0}, enrollmentId: {1}',
			certificateRequestSysId,
			enrollmentId
		);

		if (!isAutoApproved) {
			var params = {
				new_status: 'approved',
			};

			var enrollmentStatusUrl = Constants.URL.enrollmentStatusUrl.replace('{enrollment_id}', enrollmentId);

			this.logger.debug('approveManualEnrollment(): enrollmentStatusUrl: {0}', enrollmentStatusUrl);

			try {
				this.httpRequestUtils.put(enrollmentStatusUrl, params);
			} catch (error) {
				this.logger.error(
					'approveManualEnrollment(): Error ocurred on changing enrollment (enrollmentId: {0}, certificateRequestSysId: {1}) status to approved: {2}',
					enrollmentId,
					certificateRequestSysId,
					error.message
				);
				throw error;
			}
		}

		var eventName = 'x_dice_digicertone.EnrollmentCreated';
		var expiration = new GlideDateTime();
		expiration.addSeconds(3600); // 3600 seconds = 1 hour
		var payload = JSON.stringify({
			eventNumber: 1, // event number in this event's chain
			certificateRequestSysId: certificateRequestSysId,
			enrollmentId: enrollmentId,
		});
		// DEVELOPER TIP: Use gs.getUserName() and gs.getUserID() for parm1 and parm2
		// if no other values are required to see which user triggered the event in the event log.
		gs.eventQueueScheduled(eventName, '', payload, gs.getUserName(), expiration);

		this.logger.debug('approveManualEnrollment(): Added event to queue: {0}', eventName);
	},

	type: 'EnrollmentService',
};
